1408→            if (cards.length === 0) {
1409→                const chatBtns = document.querySelectorAll('[class*="btn"]');
1410→                const foundCards = new Set();
1411→                for (const btn of chatBtns) {
1412→                    if (btn.textContent?.trim() !== '立即沟通') continue;
1413→                    // Walk up to find the card container
1414→                    let card = btn.parentElement;
1415→                    for (let i = 0; i < 8 && card; i++) {
1416→                        const rect = card.getBoundingClientRect();
1417→                        if (rect.width > 200 && rect.height > 80) break;
1418→                        card = card.parentElement;
1419→                    }
1420→                    if (card) foundCards.add(card);
1421→                }
1422→                cards = Array.from(foundCards);
1423→            }
