1460→                    /^不合适$/,
1461→                    /^感兴趣$/,
1462→                    /^不感兴趣$/,
1463→                    /^发送后继续沟通$/,
1464→                    /^(\d+\s*)?年/,
1465→                    /^[|｜·]$/,
1466→                    /^在线|^离线|^活跃/,
1467→                    /^搜索/,
1468→                ];
1469→
1470→                const isSkippable = (text) => {
1471→                    return skipPatterns.some(p => p.test(text));
1472→                };
1473→
1474→                for (let i = 0; i < textParts.length; i++) {
1475→                    const part = textParts[i];
1476→                    if (isSkippable(part)) continue;
1477→
1478→                    if (!name && part.length >= 2 && part.length <= 15) {
1479→                        if (/^[\u4e00-\u9fa5a-zA-Z·\s]+$/.test(part)) {
1480→                            name = part;
1481→                            continue;
1482→                        }
1483→                    }
1484→
1485→                    if (name && !company && part.length > 1) {
1486→                        company = part;
1487→                        continue;
1488→                    }
1489→
1490→                    if (name && company && !title && part.length > 1) {
1491→                        title = part;
1492→                        break;
1493→                    }
1494→                }
1495→
1496→                if (!name) continue;
1497→
1498→                const idSource = (name || '') + '|' + (company || '') + '|' + (title || '');
1499→                let hash = 0;
1500→                for (let j = 0; j < idSource.length; j++) {
1501→                    const ch = idSource.charCodeAt(j);
