1506→
1507→                if (seenIds.has(maimaiId)) continue;
1508→                seenIds.add(maimaiId);
1509→
1510→                // Try to extract profile URL
1511→                let profileUrl = '';
1512→                const links = card.querySelectorAll('a[href]');
1513→                for (const link of links) {
