1516→                        profileUrl = href.startsWith('http') ? href : 'https://maimai.cn' + href;
1517→                        break;
1518→                    }
1519→                }
1520→
1521→                candidates.push({
1522→                    name: name,
1523→                    title: title || '',
1524→                    company: company || '',
1525→                    maimai_id: maimaiId,
1526→                    profile_url: profileUrl,
1527→                    location: '',
1528→                });
1529→            }
1530→
1531→            return candidates;
1532→        }''')
